13902 void ScalarEvolution::forgetMemoizedResultsImpl(const SCEV *S) {
13903   LoopDispositions.erase(S);
13904   BlockDispositions.erase(S);
13905   UnsignedRanges.erase(S);
13906   SignedRanges.erase(S);
13907   HasRecMap.erase(S);
13908   ConstantMultipleCache.erase(S);
13909 
13910   if (auto *AR = dyn_cast<SCEVAddRecExpr>(S)) {
13911     UnsignedWrapViaInductionTried.erase(AR);
13912     SignedWrapViaInductionTried.erase(AR);
13913   }
13914 
13915   auto ExprIt = ExprValueMap.find(S);
13916   if (ExprIt != ExprValueMap.end()) {
13917     for (Value *V : ExprIt->second) {
13918       auto ValueIt = ValueExprMap.find_as(V);
13919       if (ValueIt != ValueExprMap.end())
13920         ValueExprMap.erase(ValueIt);
13921     }
13922     ExprValueMap.erase(ExprIt);
13923   }
13924 
13925   auto ScopeIt = ValuesAtScopes.find(S);
13926   if (ScopeIt != ValuesAtScopes.end()) {
13927     for (const auto &Pair : ScopeIt->second)
13928       if (!isa_and_nonnull<SCEVConstant>(Pair.second))
13929         erase_value(ValuesAtScopesUsers[Pair.second],
13930                     std::make_pair(Pair.first, S));
13931     ValuesAtScopes.erase(ScopeIt);
13932   }
13933 
13934   auto ScopeUserIt = ValuesAtScopesUsers.find(S);
13935   if (ScopeUserIt != ValuesAtScopesUsers.end()) {
13936     for (const auto &Pair : ScopeUserIt->second)
13937       erase_value(ValuesAtScopes[Pair.second], std::make_pair(Pair.first, S));
13938     ValuesAtScopesUsers.erase(ScopeUserIt);
13939   }
13940 
13941   auto BEUsersIt = BECountUsers.find(S);
13942   if (BEUsersIt != BECountUsers.end()) {
13943     // Work on a copy, as forgetBackedgeTakenCounts() will modify the original.
13944     auto Copy = BEUsersIt->second;
13945     for (const auto &Pair : Copy)
13946       forgetBackedgeTakenCounts(Pair.getPointer(), Pair.getInt());
13947     BECountUsers.erase(BEUsersIt);
13948   }
13949 
13950   auto FoldUser = FoldCacheUser.find(S);
13951   if (FoldUser != FoldCacheUser.end())
13952     for (auto &KV : FoldUser->second)
13953       FoldCache.erase(KV);
13954   FoldCacheUser.erase(S);
