6790     // sign bits than for the value of those sign bits.
6791     unsigned NS = ComputeNumSignBits(U->getValue(), DL, 0, &AC, nullptr, &DT);
6792     if (U->getType()->isPointerTy()) {
6793       // If the pointer size is larger than the index size type, this can cause
6794       // NS to be larger than BitWidth. So compensate for this.
6795       unsigned ptrSize = DL.getPointerTypeSizeInBits(U->getType());
6796       int ptrIdxDiff = ptrSize - BitWidth;
6797       if (ptrIdxDiff > 0 && ptrSize > BitWidth && NS > (unsigned)ptrIdxDiff)
6798         NS -= ptrIdxDiff;
6799     }
6800 
6801     if (NS > 1) {
6802       // If we know any of the sign bits, we know all of the sign bits.
6803       if (!Known.Zero.getHiBits(NS).isZero())
6804         Known.Zero.setHighBits(NS);
6805       if (!Known.One.getHiBits(NS).isZero())
6806         Known.One.setHighBits(NS);
6807     }
6808 
6809     if (Known.getMinValue() != Known.getMaxValue() + 1)
6810       ConservativeResult = ConservativeResult.intersectWith(
6811           ConstantRange(Known.getMinValue(), Known.getMaxValue() + 1),
6812           RangeType);
6813     if (NS > 1)
6814       ConservativeResult = ConservativeResult.intersectWith(
6815           ConstantRange(APInt::getSignedMinValue(BitWidth).ashr(NS - 1),
6816                         APInt::getSignedMaxValue(BitWidth).ashr(NS - 1) + 1),
6817           RangeType);
6818 
6819     if (U->getType()->isPointerTy() && SignHint == HINT_RANGE_UNSIGNED) {
6820       // Strengthen the range if the underlying IR value is a global using the
6821       // size of the global.
6822       ObjectSizeOpts Opts;
6823       Opts.RoundToAlign = false;
6824       Opts.NullIsUnknownSize = true;
6825       uint64_t ObjSize;
6826       auto *GV = dyn_cast<GlobalVariable>(U->getValue());
6827       if (GV && getObjectSize(U->getValue(), ObjSize, DL, &TLI, Opts) &&
6828           ObjSize > 1) {
6829         // The highest address the object can start is ObjSize bytes before the
6830         // end (unsigned max value). If this value is not a multiple of the
6831         // alignment, the last possible start value is the next lowest multiple
6832         // of the alignment. Note: The computations below cannot overflow,
6833         // because if they would there's no possible start address for the
6834         // object.
6835         APInt MaxVal = APInt::getMaxValue(BitWidth) - APInt(BitWidth, ObjSize);
6836         uint64_t Align = GV->getAlign().valueOrOne().value();
6837         uint64_t Rem = MaxVal.urem(Align);
6838         MaxVal -= APInt(BitWidth, Rem);
6839         ConservativeResult = ConservativeResult.intersectWith(
6840             {ConservativeResult.getUnsignedMin(), MaxVal + 1}, RangeType);
6841       }
6842     }
6843 
6844     // A range of Phi is a subset of union of all ranges of its input.
6845     if (PHINode *Phi = dyn_cast<PHINode>(U->getValue())) {
6846       // Make sure that we do not run over cycled Phis.
6847       if (PendingPhiRanges.insert(Phi).second) {
6848         ConstantRange RangeFromOps(BitWidth, /*isFullSet=*/false);
6849 
6850         for (const auto &Op : Phi->operands()) {
6851           auto OpRange = getRangeRef(getSCEV(Op), SignHint, Depth + 1);
6852           RangeFromOps = RangeFromOps.unionWith(OpRange);
6853           // No point to continue if we already have a full set.
6854           if (RangeFromOps.isFullSet())
6855             break;
6856         }
6857         ConservativeResult =
6858             ConservativeResult.intersectWith(RangeFromOps, RangeType);
6859         bool Erased = PendingPhiRanges.erase(Phi);
6860         assert(Erased && "Failed to erase Phi properly?");
6861         (void)Erased;
6862       }
6863     }
6864 
6865     // vscale can't be equal to zero
6866     if (const auto *II = dyn_cast<IntrinsicInst>(U->getValue()))
6867       if (II->getIntrinsicID() == Intrinsic::vscale) {
6868         ConstantRange Disallowed = APInt::getZero(BitWidth);
6869         ConservativeResult = ConservativeResult.difference(Disallowed);
6870       }
6871 
6872     return setRange(U, SignHint, std::move(ConservativeResult));
6873   }
6874   case scCouldNotCompute:
6875     llvm_unreachable("Attempt to use a SCEVCouldNotCompute object!");
6876   }
6877 
6878   return setRange(S, SignHint, std::move(ConservativeResult));
6879 }
