6881 // Given a StartRange, Step and MaxBECount for an expression compute a range of
6882 // values that the expression can take. Initially, the expression has a value
6883 // from StartRange and then is changed by Step up to MaxBECount times. Signed
6884 // argument defines if we treat Step as signed or unsigned.
6885 static ConstantRange getRangeForAffineARHelper(APInt Step,
6886                                                const ConstantRange &StartRange,
6887                                                const APInt &MaxBECount,
6888                                                unsigned BitWidth, bool Signed) {
6889   // If either Step or MaxBECount is 0, then the expression won't change, and we
6890   // just need to return the initial range.
6891   if (Step == 0 || MaxBECount == 0)
6892     return StartRange;
6893 
6894   // If we don't know anything about the initial value (i.e. StartRange is
6895   // FullRange), then we don't know anything about the final range either.
6896   // Return FullRange.
6897   if (StartRange.isFullSet())
6898     return ConstantRange::getFull(BitWidth);
